select  from customer limit 20
--total revenue generated by male and female
SELECT gender, SUM(purchase_amount) AS total_revenue
FROM customer
GROUP BY gender;
--which customer used a discount but still spent more than a average purchase amount 
SELECT customer_id,purchase_amount
FROM customer
WHERE discount_applied = 'Yes'
AND purchase_amount  (
    SELECT AVG(purchase_amount)
    FROM customer
);
--top 5 reveiw rating products
SELECT item_purchased,
ROUND(AVG(review_ratingnumeric),2) AS AVERAGE PRODUCT RATING
FROM customer
GROUP BY item_purchased
ORDER BY AVG(review_rating) DESC
LIMIT 5;
--compare avg purchase amount between express and standard shiping
select shipping_type,avg(purchase_amount) from customer 
WHERE shipping_type IN ('Express', 'Standard')
GROUP BY shipping_type;

--do subscribed customers spent more
select subscription_status, count(customer_id) as total_customers,
ROUND(AVG(purchase_amount),2) as average_spend,
ROUND(SUM(purchase_amount),2) as total_revenue
from customer
group by subscription_status
order by total_revenue,average_spend desc;
--top5 products having the highest percentage of purchases with discounts
--applied
select item_purchased ,
ROUND(100SUM(CASE when discount_applied='Yes' then 1 else 0 end)count(),2) as discount_rate
from customer
group by item_purchased 
order by discount_rate desc 
limit 5

--segment customers into new ,returning,loyal based on their number of
--previous purchases and show the count of each segment
with customer_type as (
SELECT customer_id,previous_purchases,
case 
  when previous_purchases=1  then 'new'
  when previous_purchases Between 2 and 10 then 'returning'
  else 'loyal '
  end as customer_segment
  from customer
)
select customer_segment, count() as number of customers
from customer_type 
group by customer_segment

--top 3 products in purchased category
WITH item_count AS (
    SELECT 
        category,
        item_purchased,
        COUNT(customer_id) AS total_orders,
        ROW_NUMBER() OVER (
            PARTITION BY category 
            ORDER BY COUNT(customer_id) DESC
        ) AS item_rank
    FROM customer
    GROUP BY category, item_purchased
)
SELECT 
FROM item_count;
--are customers who are repeat buyers (more than 5 previous purchases )also likely to subscribe
WITH customer_guess AS (
    SELECT subscription_status, COUNT() AS total_customers
    FROM customer
    WHERE previous_purchases  5
    GROUP BY subscription_status
)
SELECT 
FROM customer_guess;

--revenue by each age group 
select sum(purchase_amount),count() as total_customers,age_group
from customer
group by age_group
